import React, { useEffect, useRef } from "react";
import "./DynamicBackground.css";

const getTimeGradient = () => {
  const hour = new Date().getHours();
  if (hour >= 6 && hour < 12) {
    // Morning
    return "linear-gradient(120deg, #f6d365 0%, #fda085 100%)";
  } else if (hour >= 12 && hour < 18) {
    // Afternoon
    return "linear-gradient(120deg, #a1c4fd 0%, #c2e9fb 100%)";
  } else if (hour >= 18 && hour < 20) {
    // Evening
    return "linear-gradient(120deg, #fbc2eb 0%, #a6c1ee 100%)";
  } else {
    // Night
    return "linear-gradient(120deg, #232526 0%, #414345 100%)";
  }
};

function DynamicBackground() {
  const bgRef = useRef(null);

  useEffect(() => {
    const handleMouseMove = (e) => {
      if (!bgRef.current) return;
      const { innerWidth, innerHeight } = window;
      const x = e.clientX / innerWidth;
      const y = e.clientY / innerHeight;
      bgRef.current.style.backgroundPosition = `${x * 100}% ${y * 100}%`;
    };

    window.addEventListener("mousemove", handleMouseMove);
    return () => window.removeEventListener("mousemove", handleMouseMove);
  }, []);

  useEffect(() => {
    if (bgRef.current) {
      bgRef.current.style.backgroundImage = getTimeGradient();
    }
    const interval = setInterval(() => {
      if (bgRef.current) {
        bgRef.current.style.backgroundImage = getTimeGradient();
      }
    }, 60 * 60 * 1000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div
      ref={bgRef}
      className="dynamic-bg"
      aria-hidden="true"
      tabIndex={-1}
    />
  );
}

export default DynamicBackground;
